/**
 * Send a notification: store in-memory, dispatch to all registered adapters,
 * and log to history if the history service is configured.
 */
private sendNotification(params: {
  recipient: string;
  subject: string;
  body: string;
  type: NotificationType;
}): void {
  const notification: Notification = {
    id: generateNotificationId(),
    recipient: params.recipient,
    subject: params.subject,
    body: params.body,
    sentAt: new Date(),
  };
  this.notifications.push(notification);
  this.logger.info(`Notification sent: ${notification.id} to ${params.recipient}`);

  const payload: NotificationPayload = {
    recipient: params.recipient,
    subject: params.subject,
    body: params.body,
  };

  let adapterSent = false;
  for (const adapter of this.adapters) {
    const success = adapter.send(payload);
    if (success) adapterSent = true;

    if (this.historyService) {
      this.historyService.log({
        recipient: params.recipient,
        channel: adapter.name === 'email' ? 'email' : adapter.name === 'webhook' ? 'webhook' : 'in_app',
        type: params.type,
        subject: params.subject,
        body: params.body,
        status: success ? 'sent' : 'failed',
      });
    }
  }

  // If no adapters registered, still log as in_app delivery
  if (this.adapters.length === 0 && this.historyService) {
    this.historyService.log({
      recipient: params.recipient,
      channel: 'in_app',
      type: params.type,
      subject: params.subject,
      body: params.body,
      status: 'sent',
    });
  }
}

