import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';
import {
  NotificationHistoryService,
  resetLogIdCounter,
} from '../../src/services/notification-history.service.js';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { statusChangeCallbacks } from '../../src/utils/callback-registry.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

describe('NotificationHistoryService', () => {
  let db: Database;
  let repository: NotificationLogRepository;
  let historyService: NotificationHistoryService;

  beforeEach(() => {
    db = new Database();
    repository = new NotificationLogRepository(db);
    historyService = new NotificationHistoryService(repository);
    resetLogIdCounter();
  });

  describe('log', () => {
    it('should log a notification entry', () => {
      const entry = historyService.log({
        recipient: 'alice@example.com',
        channel: 'email',
        type: 'order_confirmation',
        subject: 'Order Confirmation: order-1',
        body: 'Your order has been placed.',
        status: 'sent',
      });

      expect(entry.id).toBe('nlog-0001');
      expect(entry.recipient).toBe('alice@example.com');
      expect(entry.channel).toBe('email');
      expect(entry.type).toBe('order_confirmation');
      expect(entry.status).toBe('sent');
      expect(entry.sentAt).toBeInstanceOf(Date);
    });

    it('should generate sequential IDs', () => {
      const entry1 = historyService.log({
        recipient: 'alice@example.com',
        channel: 'email',
        type: 'order_confirmation',
        subject: 'Test 1',
        body: 'Body 1',
        status: 'sent',
      });
      const entry2 = historyService.log({
        recipient: 'bob@example.com',
        channel: 'webhook',
        type: 'order_status_update',
        subject: 'Test 2',
        body: 'Body 2',
        status: 'sent',
      });

      expect(entry1.id).toBe('nlog-0001');
      expect(entry2.id).toBe('nlog-0002');
    });

    it('should persist entries to repository', () => {
      historyService.log({
        recipient: 'alice@example.com',
        channel: 'email',
        type: 'order_confirmation',
        subject: 'Test',
        body: 'Body',
        status: 'sent',
      });

      expect(historyService.count()).toBe(1);
    });
  });

  describe('query', () => {
    beforeEach(() => {
      historyService.log({
        recipient: 'alice@example.com',
        channel: 'email',
        type: 'order_confirmation',
        subject: 'Order 1',
        body: 'Body 1',
        status: 'sent',
      });
      historyService.log({
        recipient: 'bob@example.com',
        channel: 'webhook',
        type: 'order_status_update',
        subject: 'Order 2',
        body: 'Body 2',
        status: 'sent',
      });
      historyService.log({
        recipient: 'alice@example.com',
        channel: 'email',
        type: 'order_status_update',
        subject: 'Order 3',
        body: 'Body 3',
        status: 'failed',
      });
    });

    it('should query by recipient', () => {
      const results = historyService.query({ recipient: 'alice@example.com' });
      expect(results).toHaveLength(2);
    });

    it('should query by type', () => {
      const results = historyService.query({ type: 'order_status_update' });
      expect(results).toHaveLength(2);
    });

    it('should query by channel', () => {
      const results = historyService.query({ channel: 'webhook' });
      expect(results).toHaveLength(1);
      expect(results[0]?.recipient).toBe('bob@example.com');
    });

    it('should combine multiple filters', () => {
      const results = historyService.query({
        recipient: 'alice@example.com',
        type: 'order_status_update',
      });
      expect(results).toHaveLength(1);
      expect(results[0]?.subject).toBe('Order 3');
    });

    it('should return all when no filters provided', () => {
      const results = historyService.query({});
      expect(results).toHaveLength(3);
    });

    it('should query by date range', () => {
      const past = new Date(Date.now() - 60000);
      const future = new Date(Date.now() + 60000);

      const results = historyService.query({ startDate: past, endDate: future });
      expect(results).toHaveLength(3);

      const noResults = historyService.query({
        startDate: new Date('2020-01-01'),
        endDate: new Date('2020-01-02'),
      });
      expect(noResults).toHaveLength(0);
    });
  });

  describe('queryPaginated', () => {
    beforeEach(() => {
      for (let i = 0; i < 5; i++) {
        historyService.log({
          recipient: 'alice@example.com',
          channel: 'email',
          type: 'order_confirmation',
          subject: `Order ${i}`,
          body: `Body ${i}`,
          status: 'sent',
        });
      }
    });

    it('should paginate results', () => {
      const page1 = historyService.queryPaginated({}, 1, 2);
      expect(page1.items).toHaveLength(2);
      expect(page1.totalItems).toBe(5);
      expect(page1.totalPages).toBe(3);
      expect(page1.hasNext).toBe(true);
      expect(page1.hasPrevious).toBe(false);

      const page3 = historyService.queryPaginated({}, 3, 2);
      expect(page3.items).toHaveLength(1);
      expect(page3.hasNext).toBe(false);
      expect(page3.hasPrevious).toBe(true);
    });
  });

  describe('convenience getters', () => {
    beforeEach(() => {
      historyService.log({
        recipient: 'alice@example.com',
        channel: 'email',
        type: 'order_confirmation',
        subject: 'Test',
        body: 'Body',
        status: 'sent',
      });
    });

    it('should get by recipient', () => {
      expect(historyService.getByRecipient('alice@example.com')).toHaveLength(1);
      expect(historyService.getByRecipient('unknown@example.com')).toHaveLength(0);
    });

    it('should get by type', () => {
      expect(historyService.getByType('order_confirmation')).toHaveLength(1);
      expect(historyService.getByType('order_status_update')).toHaveLength(0);
    });

    it('should get by ID', () => {
      const entry = historyService.getById('nlog-0001');
      expect(entry).toBeDefined();
      expect(entry?.recipient).toBe('alice@example.com');
    });

    it('should return undefined for unknown ID', () => {
      expect(historyService.getById('nlog-9999')).toBeUndefined();
    });

    it('should count entries', () => {
      expect(historyService.count()).toBe(1);
    });
  });
});

describe('NotificationService + NotificationHistoryService integration', () => {
  let db: Database;
  let eventBus: EventBus;
  let notificationService: NotificationService;
  let historyService: NotificationHistoryService;

  beforeEach(() => {
    db = new Database();
    eventBus = new EventBus();
    statusChangeCallbacks.clear();
    resetNotificationIdCounter();
    resetLogIdCounter();

    const repository = new NotificationLogRepository(db);
    historyService = new NotificationHistoryService(repository);

    notificationService = new NotificationService(eventBus);
    notificationService.setHistoryService(historyService);
  });

  it('should log order confirmation notifications to history', async () => {
    const event: OrderCreatedEvent = {
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [
          { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
        ],
        total: 20,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    expect(historyService.count()).toBe(1);
    const logs = historyService.getByRecipient('alice@example.com');
    expect(logs).toHaveLength(1);
    expect(logs[0]?.type).toBe('order_confirmation');
    expect(logs[0]?.channel).toBe('in_app');
    expect(logs[0]?.status).toBe('sent');
    expect(logs[0]?.subject).toContain('Order Confirmation');
  });

  it('should log order status change notifications to history', () => {
    const event: OrderStatusChangedEvent = {
      type: 'order:status-changed',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [],
        total: 20,
        status: 'confirmed',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      previousStatus: 'pending',
      newStatus: 'confirmed',
      timestamp: new Date(),
    };

    statusChangeCallbacks.notify(event);

    expect(historyService.count()).toBe(1);
    const logs = historyService.getByType('order_status_update');
    expect(logs).toHaveLength(1);
    expect(logs[0]?.recipient).toBe('user-1');
    expect(logs[0]?.status).toBe('sent');
  });

  it('should log multiple notifications and query them', async () => {
    const orderEvent: OrderCreatedEvent = {
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [
          { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
        ],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };

    await eventBus.emit(orderEvent);

    const statusEvent: OrderStatusChangedEvent = {
      type: 'order:status-changed',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [],
        total: 10,
        status: 'confirmed',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      previousStatus: 'pending',
      newStatus: 'confirmed',
      timestamp: new Date(),
    };

    statusChangeCallbacks.notify(statusEvent);

    expect(historyService.count()).toBe(2);
    expect(historyService.getByType('order_confirmation')).toHaveLength(1);
    expect(historyService.getByType('order_status_update')).toHaveLength(1);
  });
});

