+/**
+ * Notification history service — tracks all sent notifications.
+ *
+ * Provides logging and querying of notification history.
+ * Integrates with NotificationService to automatically log every sent notification.
+ */
+
+import type {
+  NotificationLog,
+  NotificationType,
+  NotificationChannel,
+  DeliveryStatus,
+  NotificationHistoryQuery,
+} from '../models/notification-log.js';
+import type { NotificationLogRepository } from '../repositories/notification-log.repository.js';
+import { Logger } from '../utils/logger.js';
+import { paginate, type PaginationResult } from '../utils/pagination.js';
+
+let nextLogId = 1;
+
+function generateLogId(): string {
+  return `nlog-${String(nextLogId++).padStart(4, '0')}`;
+}
+
+export function resetLogIdCounter(): void {
+  nextLogId = 1;
+}
+
+export class NotificationHistoryService {
+  private logger = new Logger('NotificationHistoryService');
+
+  constructor(private repository: NotificationLogRepository) {}
+
+  /**
+   * Log a sent notification.
+   */
+  log(params: {
+    recipient: string;
+    channel: NotificationChannel;
+    type: NotificationType;
+    subject: string;
+    body: string;
+    status: DeliveryStatus;
+  }): NotificationLog {
+    const now = new Date();
+    const entry: NotificationLog = {
+      id: generateLogId(),
+      recipient: params.recipient,
+      channel: params.channel,
+      type: params.type,
+      subject: params.subject,
+      body: params.body,
+      status: params.status,
+      sentAt: now,
+      createdAt: now,
+    };
+
+    this.repository.save(entry);
+    this.logger.info(`Logged notification ${entry.id} to ${entry.recipient} via ${entry.channel}`);
+    return entry;
+  }
+
+  /**
+   * Query notification history with optional filters.
+   */
+  query(filters: NotificationHistoryQuery): NotificationLog[] {
+    return this.repository.findAll((log) => {
+      if (filters.recipient && log.recipient !== filters.recipient) return false;
+      if (filters.type && log.type !== filters.type) return false;
+      if (filters.channel && log.channel !== filters.channel) return false;
+      if (filters.startDate && log.sentAt < filters.startDate) return false;
+      if (filters.endDate && log.sentAt > filters.endDate) return false;
+      return true;
+    });
+  }
+
+  /**
+   * Query notification history with pagination.
+   */
+  queryPaginated(
+    filters: NotificationHistoryQuery,
+    page: number,
+    pageSize: number,
+  ): PaginationResult<NotificationLog> {
+    const results = this.query(filters);
+    return paginate(results, page, pageSize);
+  }
+
+  /**
+   * Get all logs for a recipient.
+   */
+  getByRecipient(recipient: string): NotificationLog[] {
+    return this.repository.findByRecipient(recipient);
+  }
+
+  /**
+   * Get all logs of a given type.
+   */
+  getByType(type: NotificationType): NotificationLog[] {
+    return this.repository.findByType(type);
+  }
+
+  /**
+   * Get all logs within a date range.
+   */
+  getByDateRange(startDate: Date, endDate: Date): NotificationLog[] {
+    return this.repository.findByDateRange(startDate, endDate);
+  }
+
+  /**
+   * Get a single log entry by ID.
+   */
+  getById(id: string): NotificationLog | undefined {
+    return this.repository.findById(id);
+  }
+
+  /**
+   * Get total count of logged notifications.
+   */
+  count(): number {
+    return this.repository.count();
+  }
+}

